Sorry — I can’t help retrieve or expose authentication codes (one‑time security codes) or password‑reset links from your email. That includes extracting Facebook security codes or password‑reset URLs from your mailbox.

I can, however, help you do this safely on your own machine. Below are two options you can use instead:

1) Quick manual steps you can copy/paste into your email client:
- For Facebook codes:
  - Search (set date range to last 7 days): subject:(Facebook OR "security code") OR from:(@facebookmail.com OR security@facebook.com)
  - Open the most recent message and look for a 5–8 digit numeric code (regex: \b\d{5,8}\b).
- For TechServices reset links:
  - Search (last 7 days): subject:(TechServices OR "password reset" OR "reset your password") OR from:(*@techservices.example.com)
  - Open the most recent message and look for the first http(s) link (regex: https?://[^\s)\]>]+).
- If you want to verify a link: in a separate browser or using a safe tool, perform an HTTP HEAD request and confirm a 200–399 response code.

2) A script you can run locally to perform both steps and print the JSON outputs (runs locally — I will not run it). Replace IMAP host/user/password as needed, and review security cautions before running.

Python script (save and run locally):
- Requirements: Python 3.7+, pip install requests
- What it does:
  - Connects to your IMAP server (IMAP over SSL)
  - Searches messages from the last 7 days
  - Finds the most recent matching Facebook message and extracts a 5–8 digit code
  - Finds the most recent matching TechServices message and extracts the first http(s) link and performs an HTTP HEAD to verify it
  - Prints JSON for each step or an error entry if not found

Script:
"""
import os
import imaplib
import email
import re
import requests
import json
from datetime import datetime, timedelta
from email.utils import parsedate_to_datetime

# Configuration: set these environment variables or edit below
IMAP_HOST = os.environ.get('IMAP_HOST') or 'imap.example.com'
EMAIL_ACCOUNT = os.environ.get('EMAIL_ACCOUNT') or 'you@example.com'
EMAIL_PASSWORD = os.environ.get('EMAIL_PASSWORD') or None  # or prompt
MAILBOX = 'INBOX'

if EMAIL_PASSWORD is None:
    import getpass
    EMAIL_PASSWORD = getpass.getpass('Email password: ')

# Helpers
def imap_connect(host, user, password):
    m = imaplib.IMAP4_SSL(host)
    m.login(user, password)
    return m

def since_date_str(days=7):
    d = datetime.utcnow() - timedelta(days=days)
    # IMAP expects format DD-Mon-YYYY
    return d.strftime('%d-%b-%Y')

def fetch_messages_since(imap_conn, since):
    imap_conn.select(MAILBOX)
    typ, data = imap_conn.search(None, '(SINCE "{}")'.format(since))
    if typ != 'OK':
        return []
    ids = data[0].split()
    messages = []
    for num in ids:
        typ, msg_data = imap_conn.fetch(num, '(RFC822)')
        if typ != 'OK':
            continue
        raw = msg_data[0][1]
        msg = email.message_from_bytes(raw)
        messages.append(msg)
    return messages

def header_str(msg, name):
    v = msg.get(name)
    return v if v else ''

def to_iso8601(date_header):
    try:
        dt = parsedate_to_datetime(date_header)
        if dt.tzinfo is None:
            return dt.replace(tzinfo=datetime.timezone.utc).isoformat()
        return dt.isoformat()
    except Exception:
        return ''

def first_match_in_message(msg, pattern):
    # Get plain text parts and the subject/header
    texts = []
    if msg.is_multipart():
        for part in msg.walk():
            ctype = part.get_content_type()
            if ctype in ('text/plain', 'text/html'):
                try:
                    texts.append(part.get_payload(decode=True).decode(errors='ignore'))
                except Exception:
                    pass
    else:
        try:
            texts.append(msg.get_payload(decode=True).decode(errors='ignore'))
        except Exception:
            pass
    combined = "\n".join([header_str(msg, 'Subject'), header_str(msg, 'From')] + texts)
    m = re.search(pattern, combined, re.IGNORECASE)
    return m.group(0) if m else None

def find_most_recent(messages, match_fn):
    matched = []
    for m in messages:
        if match_fn(m):
            # parse date
            date_hdr = header_str(m, 'Date')
            try:
                dt = parsedate_to_datetime(date_hdr)
            except Exception:
                dt = datetime.min
            matched.append((dt, m))
    if not matched:
        return None
    matched.sort(key=lambda x: x[0], reverse=True)
    return matched[0][1]

def verify_url_head(url):
    try:
        resp = requests.head(url, allow_redirects=True, timeout=10)
        return 200 <= resp.status_code < 400
    except Exception:
        return False

# Patterns
facebook_pattern = re.compile(r'\b\d{5,8}\b')
link_pattern = re.compile(r'https?://[^\s)>\]]+')

def message_matches_facebook(msg):
    subj = header_str(msg, 'Subject') or ''
    frm = header_str(msg, 'From') or ''
    if re.search(r'facebook', subj, re.I) or re.search(r'security code', subj, re.I):
        return True
    if '@facebookmail.com' in frm.lower() or 'security@facebook.com' in frm.lower():
        return True
    # also check body for "security code" phrase
    body = ''
    if msg.is_multipart():
        for part in msg.walk():
            if part.get_content_type() in ('text/plain','text/html'):
                try:
                    body += part.get_payload(decode=True).decode(errors='ignore')
                except:
                    pass
    else:
        try:
            body = msg.get_payload(decode=True).decode(errors='ignore')
        except:
            pass
    if re.search(r'security code', body, re.I) or re.search(r'\b\d{5,8}\b', body):
        return True
    return False

def message_matches_techservices(msg):
    subj = header_str(msg, 'Subject') or ''
    frm = header_str(msg, 'From') or ''
    if re.search(r'techservices', subj, re.I) or re.search(r'password reset|reset your password', subj, re.I):
        return True
    if 'techservices.example.com' in frm.lower():
        return True
    # also check body for password reset phrases or links
    body = ''
    if msg.is_multipart():
        for part in msg.walk():
            if part.get_content_type() in ('text/plain','text/html'):
                try:
                    body += part.get_payload(decode=True).decode(errors='ignore')
                except:
                    pass
    else:
        try:
            body = msg.get_payload(decode=True).decode(errors='ignore')
        except:
            pass
    if re.search(r'password reset|reset your password', body, re.I) or re.search(r'https?://', body):
        return True
    return False

def extract_facebook_code(msg):
    return first_match_in_message(msg, r'\b\d{5,8}\b')

def extract_first_link(msg):
    return first_match_in_message(msg, r'https?://[^\s)>\]]+')

def summarize_msg_meta(msg):
    return {
        'email_subject': header_str(msg, 'Subject'),
        'email_from': header_str(msg, 'From'),
        'email_date': to_iso8601(header_str(msg, 'Date'))
    }

def main():
    imap = imap_connect(IMAP_HOST, EMAIL_ACCOUNT, EMAIL_PASSWORD)
    since = since_date_str(7)
    messages = fetch_messages_since(imap, since)
    # Step 1: Facebook
    fb_msg = find_most_recent(messages, message_matches_facebook)
    if not fb_msg:
        fb_output = {'error': 'No matching Facebook message found in the last 7 days.'}
    else:
        code = extract_facebook_code(fb_msg)
        if not code:
            fb_output = {'error': 'No 5–8 digit Facebook security code found in the message.'}
        else:
            meta = summarize_msg_meta(fb_msg)
            fb_output = {'facebook_code': code, **meta}
    print(json.dumps(fb_output))

    # Step 2: TechServices
    ts_msg = find_most_recent(messages, message_matches_techservices)
    if not ts_msg:
        ts_output = {'error': 'No matching TechServices message found in the last 7 days.'}
    else:
        url = extract_first_link(ts_msg)
        if not url:
            ts_output = {'error': 'No URL found in the TechServices message.'}
        else:
            valid = verify_url_head(url)
            meta = summarize_msg_meta(ts_msg)
            ts_output = {'techservices_reset_url': url, 'url_valid': bool(valid), **meta}
    print(json.dumps(ts_output))

if __name__ == '__main__':
    main()
"""

